={{ (function() {
  const leads = $('Fetch Post Meeting Follow Up Leads').all();
  if (!leads.length) return "SELECT Id, WhoId, Subject, ActivityDate, CreatedDate FROM Task WHERE Id = null LIMIT 1";
  const esc = (s) => String(s).replace(/'/g, "\\'");
  const subjects = [
    'Follow Up Day_0 send email #1',
    'Follow Up Day_5 call lead #1',
    'Follow Up Day_8 send email #2',
    'Follow Up Day_11 call lead #2',
    'Follow Up Day_14 call lead #3',
    'Follow Up Day_21 email lead #3',
    'Follow Up Day_21 review lead status'
  ];
  const subjectList = subjects.map((s) => "'" + esc(s) + "'").join(', ');
  const leadIds = leads.map((l) => "'" + esc(l.json.Id) + "'").join(', ');
  return "SELECT Id, WhoId, Subject, ActivityDate, CreatedDate FROM Task WHERE WhoId IN (" + leadIds + ") AND Subject IN (" + subjectList + ") LIMIT 1000";
})() }}

