const STEPS = [
  { key: 'Day_0', offsetDays: 0, subject: 'Follow Up Day_0 send email #1', notes: 'Email lead #1' },
  { key: 'Day_5', offsetDays: 5, subject: 'Follow Up Day_5 call lead #1', notes: 'Call lead #1' },
  { key: 'Day_8', offsetDays: 8, subject: 'Follow Up Day_8 send email #2', notes: 'Email lead #2' },
  { key: 'Day_11', offsetDays: 11, subject: 'Follow Up Day_11 call lead #2', notes: 'Call lead #2' },
  { key: 'Day_14', offsetDays: 14, subject: 'Follow Up Day_14 call lead #3', notes: 'Call lead #3' },
  { key: 'Day_21_Email', offsetDays: 21, subject: 'Follow Up Day_21 email lead #3', notes: 'Email lead' },
  { key: 'Day_21_Review', offsetDays: 21, subject: 'Follow Up Day_21 review lead status', notes: 'Review lead status' }
];

const DAY0_SUBJECT = 'Follow Up Day_0 send email #1';
const tz = 'America/Los_Angeles';
const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });

function addDays(dateStr, days) {
  const [y, m, d] = dateStr.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d + days));
  return dt.toISOString().slice(0, 10);
}

function buildStepResult(lead, step, anchorDate) {
  const leadId = String(lead.Id || '');
  const stepIndex = STEPS.findIndex((s) => s.key === step.key);
  const isFinalStep = step.key === 'Day_21_Review';
  const effectiveAnchor = anchorDate || todayStr;
  const isDay0Bootstrap = step.offsetDays === 0 && !anchorDate;
  const rawDueDateStr = isDay0Bootstrap ? todayStr : addDays(effectiveAnchor, step.offsetDays);
  let nextFollowUpRawDateStr = '';
  if (!isFinalStep && step.key !== 'Day_21_Email') {
    const nextStep = STEPS[stepIndex + 1];
    nextFollowUpRawDateStr = addDays(effectiveAnchor, nextStep.offsetDays);
  }
  return {
    json: {
      leadId,
      sequenceKey: leadId + '_PostMeeting',
      leadName: String(lead.Name || ''),
      leadEmail: String(lead.Email || ''),
      leadOwnerId: String(lead.OwnerId || ''),
      anchorDate: effectiveAnchor,
      stepKey: step.key,
      stepIndex,
      taskSubject: step.subject,
      taskNotes: step.notes,
      isFinalStep,
      rawDueDateStr,
      nextFollowUpRawDateStr,
      nextDueDateStr: nextFollowUpRawDateStr,
      todayStr
    }
  };
}

const tasksByLead = {};
const day0AnchorByLead = {};

for (const t of $('Fetch Sequence Tasks (Batch)').all()) {
  const who = String(t.json.WhoId || '');
  const subj = String(t.json.Subject || '');
  if (!who || !subj) continue;
  if (!tasksByLead[who]) tasksByLead[who] = new Set();
  tasksByLead[who].add(subj);

  if (subj === DAY0_SUBJECT) {
    const activityDate = String(t.json.ActivityDate || '').slice(0, 10);
    const createdDate = String(t.json.CreatedDate || '').slice(0, 10);
    const anchor = activityDate || createdDate;
    if (anchor && (!day0AnchorByLead[who] || anchor < day0AnchorByLead[who])) {
      day0AnchorByLead[who] = anchor;
    }
  }
}

const results = [];

for (const item of $('Fetch Post Meeting Follow Up Leads').all()) {
  const lead = item.json;
  const leadId = String(lead.Id || '');
  if (!leadId) continue;

  const existingSubjects = tasksByLead[leadId] || new Set();
  const anchorDate = day0AnchorByLead[leadId] || null;
  const stepsToCreate = [];

  if (!anchorDate) {
    if (!existingSubjects.has(DAY0_SUBJECT)) {
      stepsToCreate.push(STEPS[0]);
    }
  } else {
    for (let i = 1; i < STEPS.length; i++) {
      const step = STEPS[i];
      if (existingSubjects.has(step.subject)) continue;

      if (step.offsetDays < 21) {
        stepsToCreate.push(step);
        break;
      }

      if (step.offsetDays === 21) {
        for (let j = i; j < STEPS.length; j++) {
          const day21Step = STEPS[j];
          if (day21Step.offsetDays !== 21) break;
          if (!existingSubjects.has(day21Step.subject)) {
            stepsToCreate.push(day21Step);
          }
        }
        break;
      }
    }
  }

  for (const step of stepsToCreate) {
    const built = buildStepResult(lead, step, anchorDate);
    // Only create when raw calendar due date is today or earlier (no W11 business-day adjustment)
    if (built.json.rawDueDateStr > todayStr) continue;
    results.push(built);
  }
}

return results;

parameters.query:
={{ (function() {
  const items = $('Determine Due Sequence Step').all();
  if (!items.length) return "SELECT Id, WhoId, Subject FROM Task WHERE Id = null LIMIT 1";
  const esc = (s) => String(s).replace(/'/g, "\\'");
  const conditions = items.map((i) => "(WhoId = '" + esc(i.json.leadId) + "' AND Subject = '" + esc(i.json.taskSubject) + "')").join(' OR ');
  return "SELECT Id, WhoId, Subject FROM Task WHERE " + conditions + " LIMIT " + (items.length + 10);
})() }}

