const existing = new Set();
for (const t of $('Check Existing Tasks (Batch)').all()) {
  const who = String(t.json.WhoId || '');
  const subj = String(t.json.Subject || '');
  if (!who || !subj) continue;
  existing.add(who + '|' + subj);
}

const results = [];
for (const item of $('Determine Due Sequence Step').all()) {
  const d = item.json;
  const key = d.leadId + '|' + d.taskSubject;
  results.push({ json: { ...d, taskExists: existing.has(key) } });
}
return results;

const normalizeItems = $('Normalize Task Existence').all();
const results = [];
for (const item of $input.all()) {
  const pi = item.pairedItem?.item;
  if (pi === undefined || pi === null) continue;
  const ctx = normalizeItems[pi]?.json;
  if (!ctx || !ctx.leadId || ctx.taskExists === true) continue;
  results.push({ json: { ...ctx } });
}
return results;
